class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = {}
        count_t = {}

        for char in s:
            count_s[char] = count_s.get(char, 0) + 1
        for char in t:
            count_t[char] = count_t.get(char, 0) + 1

        steps = 0
        for char in count_s:
            steps += abs(count_s[char] - count_t.get(char, 0))

        return steps // 2
```
efficiency: HIGH
time complexity: O(n)
space complexity: O(n)
